mapper.select:
SELECT u.user_code AS userCode, u.name AS userName, SUM(CASE WHEN s.code_id = 'OB1' THEN 1 ELSE 0 END) AS newIss, SUM(CASE WHEN s.code_id = 'OB2' THEN 1 ELSE 0 END) AS progress, SUM(CASE WHEN s.code_id = 'OB3' THEN 1 ELSE 0 END) AS solution, SUM(CASE WHEN s.code_id = 'OB4' THEN 1 ELSE 0 END) AS returnIss, SUM(CASE WHEN s.code_id = 'OB5' THEN 1 ELSE 0 END) AS completion FROM issues i JOIN status s ON s.status_code = i.status_code JOIN users u ON u.user_code = i.assignee_code
WHERE i.project_code = #{projectCode} AND i.assignee_code = #{userCode}
GROUP BY u.user_code, u.name

SELECT * FROM ( SELECT n.notice_code AS noticeCode, n.project_code AS projectCode, p.project_name AS projectName, n.title AS title, n.created_at AS createdAt FROM projects p JOIN ( SELECT pru.project_code FROM project_role_user pru WHERE pru.user_code = #{userCode}
UNION
SELECT gpr.project_code FROM "GROUP_MEMBER" gm JOIN "GR_PRO_ROLE" gpr ON gpr.gr_code = gm.gr_code WHERE gm.user_code = #{userCode} ) up ON up.project_code = p.project_code
JOIN notices n ON n.project_code = p.project_code
WHERE p.status = 'OD1' ORDER BY n.created_at DESC ) WHERE ROWNUM <= #{limit}
